import React, {useState} from "react";
import './Welcome.css';

function Welcome () {
    const [userName, setUserName] = useState('');
    const [passWord, setPassWord] = useState('');
    const [isLoginSuccessful, setIsLoginSuccessful] = useState(false);
    const [invalidCreds, setInvalidCreds] = useState(false);

    const handleUsernameChange = (e) => {
        e.preventDefault();
        const value = e.target.value;
        setUserName(value);
    }
    const handlePasswordChange = (e) => {
        e.preventDefault();
        const value = e.target.value;
        setPassWord(value);
    }
    const Login = (e) => {
        e.preventDefault();
        // const value = e.target.value;
        if (userName === 'admin' && passWord === '1234') {
            setIsLoginSuccessful(true);
            Credentials(isLoginSuccessful);
        }
        else {
            setInvalidCreds(true);
            InvalidCredentials(invalidCreds);
            setIsLoginSuccessful(false);
            Credentials(isLoginSuccessful);
        }
    }
    const Credentials = () => {
        if (isLoginSuccessful)  
        {  
        return <div>Success!</div>;
        }
    }
    const InvalidCredentials = () => {
        if (invalidCreds)  
        {  
            return (
                        <div className="error">Invalid Credential!</div>
                    )
        }
    }
    return  (
    <div>
        <Credentials></Credentials>
        <InvalidCredentials></InvalidCredentials>
        <h1 className = 'title'>Welcome to Productiv!</h1>
        <form className = 'location-form'>
            <div>
            <label htmlFor="username">Username </label>
            <input type="text" id="username" name="username" value = {userName} onChange = {handleUsernameChange}></input>
            </div>
            <div>
            <label htmlFor="password">Password </label>
            <input type="password" id="password" name="password" value = {passWord} onChange = {handlePasswordChange}></input>
            </div>
            <div>
            <button className ='button' type="submit" value= {isLoginSuccessful} onClick={Login}>Login</button>
            <button className ='button' type="submit" value= "Sign up">Sign up</button>
            </div>
        </form>
    </div>
    )
    }

export default Welcome;
